"use strict";(self.webpackChunklynx_onboarding_docs=self.webpackChunklynx_onboarding_docs||[]).push([[692],{5578(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","href":"/LYNX-Onboarding-Setup/docs/intro","label":"LYNX Real Estate Group Onboarding Guide","docId":"intro","unlisted":false},{"type":"category","label":"Module 1 \xb7 Welcome to the Team","items":[{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-1/team-values","label":"1.1 Our Team & What We Stand For","docId":"module-1/team-values","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-1/team-structure","label":"1.2 Team Structure & Who to Ask","docId":"module-1/team-structure","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-1/first-30-days","label":"1.3 Your First 30 Days","docId":"module-1/first-30-days","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-1/alberta-licensing","label":"1.4 Alberta Licensing in Plain English","docId":"module-1/alberta-licensing","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-1/team-expectations-culture","label":"1.5 Team Expectations & Culture","docId":"module-1/team-expectations-culture","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Module 2 \xb7 Your Tech Stack","items":[{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-2/follow-up-boss","label":"2.1 Follow Up Boss","docId":"module-2/follow-up-boss","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-2/mls-showingtime","label":"2.2 MLS & ShowingTime","docId":"module-2/mls-showingtime","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-2/marketing-tools","label":"2.3 Marketing Tools","docId":"module-2/marketing-tools","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-2/team-communication","label":"2.4 Team Communication","docId":"module-2/team-communication","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-2/digital-documents-esignatures","label":"2.5 Digital Documents & E-Signatures","docId":"module-2/digital-documents-esignatures","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Module 3 \xb7 Working With Buyers","items":[{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-3/inbound-lead-call","label":"3.1 \u2014 The Inbound Buyer Lead Call","docId":"module-3/inbound-lead-call","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-3/buyer-consultation","label":"3.2 The Buyer Consultation","docId":"module-3/buyer-consultation","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-3/showings","label":"3.3 Showings","docId":"module-3/showings","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-3/writing-presenting-offer","label":"3.4 Writing & Presenting an Offer","docId":"module-3/writing-presenting-offer","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-3/offer-to-close","label":"3.5 Offer to Close","docId":"module-3/offer-to-close","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Module 4 \xb7 Working With Sellers","items":[{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-4/pre-listing-prep","label":"4.1 Pre-Listing Prep","docId":"module-4/pre-listing-prep","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-4/listing-appointment","label":"4.2 The Listing Appointment","docId":"module-4/listing-appointment","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-4/listing-launch","label":"4.3 Listing Launch","docId":"module-4/listing-launch","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-4/offers-negotiation-listing-side","label":"4.4 Offers & Negotiation on the Listing Side","docId":"module-4/offers-negotiation-listing-side","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-4/seller-communication-cadence","label":"4.5 Seller Communication Cadence","docId":"module-4/seller-communication-cadence","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Module 5 \xb7 Building Your Business","items":[{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-5/how-leads-work","label":"5.1 How Leads Work on Our Team","docId":"module-5/how-leads-work","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-5/sphere-of-influence","label":"5.2 Your Sphere of Influence","docId":"module-5/sphere-of-influence","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-5/scripts-objection-handling","label":"5.3 Scripts & Objection Handling","docId":"module-5/scripts-objection-handling","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-5/open-houses","label":"5.4 Open Houses","docId":"module-5/open-houses","unlisted":false},{"type":"link","href":"/LYNX-Onboarding-Setup/docs/module-5/reviews-referrals-staying-in-touch","label":"5.5 Reviews, Referrals & Staying in Touch","docId":"module-5/reviews-referrals-staying-in-touch","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"intro":{"id":"intro","title":"LYNX Real Estate Group Onboarding Guide","description":"Welcome to the LYNX onboarding portal","sidebar":"docsSidebar"},"module-1/alberta-licensing":{"id":"module-1/alberta-licensing","title":"1.4 Alberta Licensing in Plain English","description":"Your licensing course taught you the rules. This section tells you what those rules actually mean when you\'re sitting across from a client. When in doubt on anything compliance-related \u2014 call your Mentor. Never guess.","sidebar":"docsSidebar"},"module-1/first-30-days":{"id":"module-1/first-30-days","title":"1.3 Your First 30 Days","description":"This is your roadmap for month one. Work through it week by week and bring it to every check-in. Completion of this checklist is required before your 30-day review with your Mentor.","sidebar":"docsSidebar"},"module-1/team-expectations-culture":{"id":"module-1/team-expectations-culture","title":"1.5 Team Expectations & Culture","description":"This isn\'t a list of rules to memorize. It\'s how we operate. The agents who thrive at Lynx aren\'t just good at real estate \u2014 they\'re good teammates. Read this once, then come back to it if something feels off.","sidebar":"docsSidebar"},"module-1/team-structure":{"id":"module-1/team-structure","title":"1.2 Team Structure & Who to Ask","description":"You will have questions you don\'t know the answer to. That\u2019s expected and normal. What matters is knowing who to ask \u2014 and asking before your client notices you don\u2019t know.","sidebar":"docsSidebar"},"module-1/team-values":{"id":"module-1/team-values","title":"1.1 Our Team & What We Stand For","description":"Who we are","sidebar":"docsSidebar"},"module-2/digital-documents-esignatures":{"id":"module-2/digital-documents-esignatures","title":"2.5 Digital Documents & E-Signatures","description":"\ud83d\udcc4 Every offer, listing agreement, and representation agreement you touch will be handled digitally. Knowing how to send, track, and organize documents properly is not optional \u2014 a missed signature or a misfiled document can delay or kill a deal.","sidebar":"docsSidebar"},"module-2/follow-up-boss":{"id":"module-2/follow-up-boss","title":"2.1 Follow Up Boss","description":"Follow Up Boss is your command centre. Every lead, every conversation, every follow-up lives here. If it isn\'t in FUB, it didn\'t happen. Master this before anything else in Module 2.","sidebar":"docsSidebar"},"module-2/marketing-tools":{"id":"module-2/marketing-tools","title":"2.3 Marketing Tools","description":"Your marketing is your brand. Every post, every graphic, every piece of content you put out represents you and Lynx. Done well, it builds trust before a client ever meets you. Done poorly, it costs you deals you\'ll never know you lost.","sidebar":"docsSidebar"},"module-2/mls-showingtime":{"id":"module-2/mls-showingtime","title":"2.2 MLS & ShowingTime","description":"MLS is where every active listing in Calgary lives. ShowingTime is how you book access to them. You\'ll use both of these every single day \u2014 knowing them well makes you look like a pro in front of clients from day one.","sidebar":"docsSidebar"},"module-2/team-communication":{"id":"module-2/team-communication","title":"2.4 Team Communication","description":"Slack is how the Lynx team operates day to day. Good communication here makes everything run smoother \u2014 for you, for your clients, and for the team. Learn how we use it in the first week and it becomes second nature fast.","sidebar":"docsSidebar"},"module-3/buyer-consultation":{"id":"module-3/buyer-consultation","title":"3.2 The Buyer Consultation","description":"","sidebar":"docsSidebar"},"module-3/inbound-lead-call":{"id":"module-3/inbound-lead-call","title":"3.1 \u2014 The Inbound Buyer Lead Call","description":"\ud83d\udcde This is the highest-leverage conversation in real estate. You have one shot to turn a stranger into an appointment. Everything else in Module 3 depends on getting this right first. Read this section before you take a single lead call \u2014 then keep the script beside you for your first 90 days.","sidebar":"docsSidebar"},"module-3/offer-to-close":{"id":"module-3/offer-to-close","title":"3.5 Offer to Close","description":"","sidebar":"docsSidebar"},"module-3/showings":{"id":"module-3/showings","title":"3.3 Showings","description":"","sidebar":"docsSidebar"},"module-3/writing-presenting-offer":{"id":"module-3/writing-presenting-offer","title":"3.4 Writing & Presenting an Offer","description":"","sidebar":"docsSidebar"},"module-4/listing-appointment":{"id":"module-4/listing-appointment","title":"4.2 The Listing Appointment","description":"A listing appointment is a structured conversation, not a presentation. The agents who win listings consistently aren\'t the ones who talk the most \u2014 they\'re the ones who listen first, then lead with confidence.","sidebar":"docsSidebar"},"module-4/listing-launch":{"id":"module-4/listing-launch","title":"4.3 Listing Launch","description":"Going live on MLS is a moment you only get once with each listing. The first 72 hours drive more traffic \u2014 and more offers \u2014 than any other point in the listing lifecycle. Get the launch right.","sidebar":"docsSidebar"},"module-4/offers-negotiation-listing-side":{"id":"module-4/offers-negotiation-listing-side","title":"4.4 Offers & Negotiation on the Listing Side","description":"An offer on the table is the moment everything you\'ve done as a listing agent gets tested. How you handle the next few hours determines whether your seller walks away feeling like they got the best possible outcome \u2014 or not.","sidebar":"docsSidebar"},"module-4/pre-listing-prep":{"id":"module-4/pre-listing-prep","title":"4.1 Pre-Listing Prep","description":"You win the listing before you walk in the door. The preparation you do in the 24 hours before a seller appointment is what separates an agent who gets hired from one who gets thanked and shown out.","sidebar":"docsSidebar"},"module-4/seller-communication-cadence":{"id":"module-4/seller-communication-cadence","title":"4.5 Seller Communication Cadence","description":"\ud83d\udcde The listing agreement is a contract. The communication cadence is the relationship. Sellers who feel informed and respected stay calm, stay rational, and make better decisions. Sellers who feel ignored get anxious, second-guess everything, and blame their agent when things get hard.","sidebar":"docsSidebar"},"module-5/how-leads-work":{"id":"module-5/how-leads-work","title":"5.1 How Leads Work on Our Team","description":"Leads are the lifeblood of this business. Understanding how they\'re assigned, tracked, and protected isn\'t optional \u2014 it\'s foundational. Read this carefully.","sidebar":"docsSidebar"},"module-5/open-houses":{"id":"module-5/open-houses","title":"5.4 Open Houses","description":"An open house isn\'t just a favour to the seller. Done right, it\'s one of the highest-leverage lead generation activities you have. Two hours on a Sunday can change your pipeline for the month.","sidebar":"docsSidebar"},"module-5/reviews-referrals-staying-in-touch":{"id":"module-5/reviews-referrals-staying-in-touch","title":"5.5 Reviews, Referrals & Staying in Touch","description":"Closing the deal is the beginning of the relationship, not the end of it. The clients who feel taken care of after the transaction are the ones who send you business for the next ten years.","sidebar":"docsSidebar"},"module-5/scripts-objection-handling":{"id":"module-5/scripts-objection-handling","title":"5.3 Scripts & Objection Handling","description":"Every objection is a question in disguise. Your job isn\'t to overcome it \u2014 it\'s to understand what\'s behind it and respond with confidence. Keep responses short. Never argue. Always follow up with a question.","sidebar":"docsSidebar"},"module-5/sphere-of-influence":{"id":"module-5/sphere-of-influence","title":"5.2 Your Sphere of Influence","description":"No lead source will ever outperform the people who already know, like, and trust you. Your sphere isn\'t a backup plan \u2014 it\'s the foundation of a long-term real estate career.","sidebar":"docsSidebar"}}}}')}}]);